class Solution(object):
    def maxRectangleArea(self, points):
        pt_set = set(map(tuple, points))
        ans = -1
        n = len(points)
        for i in range(n):
            for j in range(i+1, n):
                x1, y1 = points[i]
                x2, y2 = points[j]
                if x1 == x2 or y1 == y2:
                    continue
                # (x1,y1) and (x2,y2) are opposite corners
                if (x1,y2) not in pt_set or (x2,y1) not in pt_set:
                    continue
                # Check no other point lies inside or on border
                lx, rx = min(x1,x2), max(x1,x2)
                ly, ry = min(y1,y2), max(y1,y2)
                valid = True
                for px, py in points:
                    if lx <= px <= rx and ly <= py <= ry:
                        if (px, py) not in {(x1,y1),(x2,y2),(x1,y2),(x2,y1)}:
                            valid = False
                            break
                if valid:
                    area = (rx - lx) * (ry - ly)
                    ans = max(ans, area)
        return ans
